int square(int n) {
    return n * n;
}

int factorial(int n) {
    if (n == 0) return 1;     // বেস কেস
    return n * factorial(n - 1); // রিকার্সিভ কল
}

int main() {
    printf("5! = %d\n", factorial(5)); // 120
    return 0;
}
